using UnityEngine;

public class ProceduralEnvironmentGenerator : MonoBehaviour
{
    [Header("Terrain Settings")]
    public int width = 256;
    public int depth = 256;
    public int height = 20;
    public float scale = 20f;

    [Header("User Preferences")]
    public float preferenceInfluence = 0.5f; // Value between 0-1

    private Terrain terrain;

    void Start()
    {
        terrain = GetComponent<Terrain>();
        terrain.terrainData = GenerateTerrain(terrain.terrainData);
    }

    TerrainData GenerateTerrain(TerrainData terrainData)
    {
        terrainData.heightmapResolution = width + 1;
        terrainData.size = new Vector3(width, height, depth);
        terrainData.SetHeights(0, 0, GenerateHeights());
        return terrainData;
    }

    float[,] GenerateHeights()
    {
        float[,] heights = new float[width, depth];
        for (int x = 0; x < width; x++)
        {
            for (int z = 0; z < depth; z++)
            {
                float xCoord = (float)x / width * scale;
                float zCoord = (float)z / depth * scale;
                float baseHeight = Mathf.PerlinNoise(xCoord, zCoord);
                heights[x, z] = Mathf.Lerp(baseHeight, UserPreferenceAdjustedHeight(xCoord, zCoord), preferenceInfluence);
            }
        }
        return heights;
    }

    float UserPreferenceAdjustedHeight(float x, float z)
    {
        // Simulate user preference adjustments, could be based on user data
        // For simplicity, let's assume a basic modification
        return Mathf.PerlinNoise(x * 0.3f, z * 0.3f) + Mathf.Sin(x * 0.1f) * Mathf.Cos(z * 0.1f);
    }
}

using NUnit.Framework;
using UnityEngine;
using UnityEngine.TestTools;
using System.Collections;
using UnityEngine.SceneManagement;

public class EnvironmentStabilityTests
{
    // Test that the environment loads within an acceptable time frame
    [UnityTest]
    public IEnumerator TestEnvironmentLoadTime()
    {
        // Start the timer
        var startTime = Time.realtimeSinceStartup;

        // Load the scene (replace "EnvironmentScene" with your actual scene name)
        yield return SceneManager.LoadSceneAsync("EnvironmentScene");

        // Calculate load time
        var loadTime = Time.realtimeSinceStartup - startTime;

        // Assert that load time is under 5 seconds
        Assert.Less(loadTime, 5.0f, "Environment loading took too long!");
    }

    // Test that the frame rate is stable
    [UnityTest]
    public IEnumerator TestFrameRateStability()
    {
        // Allow the scene to initialize
        yield return null;

        // Measure frame rate over 5 seconds
        float startTime = Time.realtimeSinceStartup;
        int frameCount = 0;

        while (Time.realtimeSinceStartup - startTime < 5.0f)
        {
            frameCount++;
            yield return null;
        }

        // Calculate average frame rate
        float averageFrameRate = frameCount / 5.0f;

        // Assert that the average frame rate is above 60 FPS
        Assert.Greater(averageFrameRate, 60.0f, "Average frame rate is below 60 FPS");
    }

    // Test memory usage to ensure it is within acceptable limits
    [UnityTest]
    public IEnumerator TestMemoryUsage()
    {
        // Allow the scene to initialize
        yield return null;

        // Measure memory usage
        long memoryUsage = System.GC.GetTotalMemory(false);

        // Assert that memory usage is below 500 MB
        Assert.Less(memoryUsage / (1024 * 1024), 500, "Memory usage exceeded 500 MB");
    }
}

